// Prevents additional console window on Windows in release, DO NOT REMOVE!!
#![cfg_attr(not(debug_assertions), windows_subsystem = "windows")]

use clap::{Parser, Subcommand};
use std::path::PathBuf;

/// Real-time character-grid image renderer.
///
/// Default behavior with no subcommand: launches the visual studio (GUI).
/// Subcommands provide headless operation for scripts and AI agents.
#[derive(Parser, Debug)]
#[command(name = "glyph-grid-studio", version, about, long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Option<Command>,
}

#[derive(Subcommand, Debug)]
enum Command {
    /// Launch the visual studio (default if no subcommand given).
    Studio,

    /// Render a single image to an animated GIF, headlessly.
    Render(RenderArgs),

    /// Render many variants of the SAME source in ONE Tauri session.  Reads a
    /// manifest JSON with `{in, frames, jobs:[{name,out,format?,config}, ...]}`
    /// and runs all jobs back-to-back without re-launching the app per variant.
    /// ~10× faster than calling `render` repeatedly because Tauri startup +
    /// source-image decode happens once.  See ITER-024 in BUGS_AND_ITERATIONS.md.
    Batch(BatchArgs),

    /// Print the catalog of available palettes / ramps / dithers / glyph sets / postprocess stages.
    Catalog,

    /// Run the MCP server (Model Context Protocol over stdio JSON-RPC).
    /// Wire this into Claude Desktop / Cursor via their MCP config; tools then
    /// appear as `glyph_grid_render` and `glyph_grid_catalog`.
    Mcp,
}

use base64::engine::general_purpose;
use base64::Engine as _;
use serde::{Deserialize, Serialize};
use std::fs;
use std::io::Cursor;
use std::path::PathBuf;
use std::sync::{Arc, Mutex};
use tauri::Manager;
use tauri_plugin_dialog::DialogExt;

pub mod mcp;

/* ============================================================================
 *  CLI / headless-render plumbing.
 *
 *  When the binary is launched with `render --in foo --out bar`, main.rs
 *  builds a HeadlessRenderJob and calls run_headless_render(). That function
 *  spins up a Tauri runtime with a hidden window, stores the job in managed
 *  state, and waits for the JS side to call exit_with_status() when done.
 *  The same rendering pipeline is used as the GUI path — only the entry +
 *  exit are different.
 * ============================================================================ */

#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct ConfigOverrides {
    pub palette: Option<String>,
    pub color_mode: Option<String>,
    pub ramp: Option<String>,
    pub dither_mode: Option<String>,
    pub selection_mode: Option<String>,
    pub glyph_set: Option<String>,
    pub sampling_strategy: Option<String>,
    pub postprocess: Vec<String>,
    pub cols: Option<u32>,
    pub rows: Option<u32>,
}

#[derive(Debug, Clone)]
pub struct HeadlessRenderJob {
    pub in_path: PathBuf,
    pub out_path: PathBuf,
    pub frames: u32,
    pub show_window: bool,
    pub preset_path: Option<PathBuf>,
    pub config_overrides: ConfigOverrides,
    /// Output format. `"gif"` (default) → gifski; `"mp4"` → openh264 + mp4.
    /// When None, derived from `out_path`'s extension.
    pub format: Option<String>,
}

#[tauri::command]
fn get_cli_render_job(state: tauri::State<CliJobState>) -> Option<serde_json::Value> {
    state.job.lock().ok().and_then(|g| g.clone())
}

/// JS-side log forwarding for headless / production builds where
/// `console.log` doesn't reach stderr.  Useful for surfacing batch errors.
#[tauri::command]
fn cli_log(msg: String) {
    eprintln!("glyph-grid-studio[js]: {}", msg);
}

